		size_t n = 128, i = 0;
		int c;
		char *ln = malloc(128);
		while ((c = fgetc(fp)) != EOF && c != '\\n') {
			if (i >= n - 2) {
				n += 128;
				ln = erealloc(ln, n);
			}
			ln[i++] = c;
		}
		if (c == EOF) {
			free(ln);
			done = 1;
			break;
		}
		if (ln[0] != '#' && ln[0] != '\\n') { /* not a comment or empty line */
